mapper.select:
select notification_id, user_id, type, title, content, related_type, related_id, is_read, read_at, create_at
from notification
where user_id = #{userId}

    and type = #{type}


    and is_read = #{isRead}

order by create_at desc

mapper.update:
update notification
is_read = #{isRead}, read_at = now(),
where notification_id = #{notificationId}
